fn scan_operator() -> token_t {
    let mut buf = Vec::with_capacity(2);
    let c = peek_char();
    buf.push(advance_char());
    let next = peek_char();

    let two = matches!(
        (c, next),
        (b'=', b'=')
            | (b'!', b'=')
            | (b'<', b'=')
            | (b'>', b'=')
            | (b'&', b'&')
            | (b'|', b'|')
            | (b'+', b'+')
            | (b'-', b'-')
            | (b'-', b'>')
            | (b'<', b'<')
            | (b'>', b'>')
    );
    if two {
        buf.push(advance_char());
    }
    create_token(TOKEN_OPERATOR, &buf)
}

fn is_operator_char(c: u8) -> bool {
    matches!(
        c,
        b'+' | b'-'
